#!/bin/bash\n# Quick start script for SMS Transaction Analyzer\n\necho \"======================================\"\necho \"SMS Transaction Analyzer - Quick Start\"\necho \"======================================\"\necho \"\"\n\n# Step 1: Check Flutter\necho \"[1/5] Checking Flutter installation...\"\nif ! command -v flutter &> /dev/null; then\n    echo \"❌ Flutter not found. Please install Flutter first.\"\n    exit 1\nfi\necho \"✅ Flutter found: $(flutter --version | head -n 1)\"\necho \"\"\n\n# Step 2: Get dependencies\necho \"[2/5] Getting dependencies...\"\nflutter pub get\nif [ $? -ne 0 ]; then\n    echo \"❌ Failed to get dependencies\"\n    exit 1\nfi\necho \"✅ Dependencies installed\"\necho \"\"\n\n# Step 3: Generate code\necho \"[3/5] Generating code (Drift, Freezed, Riverpod)...\"\necho \"This may take a minute...\"\nflutter pub run build_runner build --delete-conflicting-outputs\nif [ $? -ne 0 ]; then\n    echo \"❌ Code generation failed\"\n    echo \"Try running: flutter pub run build_runner clean\"\n    exit 1\nfi\necho \"✅ Code generation complete\"\necho \"\"\n\n# Step 4: Check for errors\necho \"[4/5] Checking for compilation errors...\"\nflutter analyze\nif [ $? -ne 0 ]; then\n    echo \"⚠️  Some lint warnings found (this is OK for development)\"\nfi\necho \"✅ Analysis complete\"\necho \"\"\n\n# Step 5: Ready to run\necho \"[5/5] Ready to run!\"\necho \"\"\necho \"Next steps:\"\necho \"1. Connect an Android device or start an emulator\"\necho \"2. Run: flutter run\"\necho \"3. Grant SMS permission when prompted\"\necho \"\"\necho \"For testing:\"\necho \"  flutter test\"\necho \"\"\necho \"For running on specific device:\"\necho \"  flutter devices          # See available devices\"\necho \"  flutter run -d <device>  # Run on specific device\"\necho \"\"\necho \"======================================\"\necho \"Setup complete! 🎉\"\necho \"======================================\"\n